#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k04593Custom {
public:
    __aicore__ inline KernelCa6k04593Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t batch, uint32_t channels,
                                uint32_t depth, uint32_t height, uint32_t width,
                                float eps)
    {
        batch_ = batch;
        channels_ = channels;
        depth_ = depth;
        height_ = height;
        width_ = width;
        spatialSize_ = depth * height * width;
        totalRows_ = batch * channels;
        eps_ = eps;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalRows_ * spatialSize_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalRows_ * spatialSize_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, spatialSize_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, spatialSize_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, spatialSize_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalRows_ == 0 || spatialSize_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        uint32_t localSpatial = spatialSize_;
        uint32_t row = blockIdx;
        while (row < totalRows_) {
            uint32_t offset = row * localSpatial;

            // Copy input
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], localSpatial);

            // Compute mean
            AscendC::LocalTensor<float> meanBuf = tmpQueue_.AllocTensor<float>();
            AscendC::ReduceSum(meanBuf, xLocal, localSpatial);
            float mean = meanBuf(0) / static_cast<float>(localSpatial);
            tmpQueue_.FreeTensor(meanBuf);

            // Subtract mean
            AscendC::LocalTensor<float> meanVec = tmpQueue_.AllocTensor<float>();
            AscendC::Duplicate(meanVec, mean, localSpatial);
            AscendC::Sub(xLocal, xLocal, meanVec, localSpatial);
            tmpQueue_.FreeTensor(meanVec);

            // Compute variance
            AscendC::LocalTensor<float> sqBuf = tmpQueue_.AllocTensor<float>();
            AscendC::Mul(sqBuf, xLocal, xLocal, localSpatial);
            AscendC::LocalTensor<float> varBuf = tmpQueue_.AllocTensor<float>();
            AscendC::ReduceSum(varBuf, sqBuf, localSpatial);
            float var = varBuf(0) / static_cast<float>(localSpatial);
            tmpQueue_.FreeTensor(varBuf);
