            AscendC::Muls(xLocal, xLocal, invStd, localSpatial);

            // Copy output
            AscendC::DataCopy(yGm_[offset], xLocal, localSpatial);

            inQueueX_.FreeTensor(xLocal);

            row += blockNum;
        }
    }

